'use client';

import { useEffect, useState } from 'react';
import { usePathname } from 'next/navigation';
import NotificationBell from '../components/NotificationBell';
import { MinimalUser } from '../lib/storage';

// Pages where notification bell should NOT appear
const EXCLUDED_PATHS = [
  '/login',
  '/register', 
  '/forgot-password',
  '/auth/callback'
];

export default function GlobalNotificationBell() {
  const [userId, setUserId] = useState<string | null>(null);
  const [hasToken, setHasToken] = useState<boolean>(false);
  const pathname = usePathname();

  useEffect(() => {
    if (typeof window !== 'undefined') {
      const userData = localStorage.getItem('ecokonek_user');
      const token = localStorage.getItem('ecokonek_token');
      if (userData) {
        try {
          const user: MinimalUser = JSON.parse(userData);
          if (user.id) setUserId(user.id);
        } catch (e) {
          setUserId(null);
        }
      }
      setHasToken(!!token);

      // Listen to storage changes (logout/login across tabs or token refresh)
      const onStorage = (e: StorageEvent) => {
        if (!e.key || e.key === 'ecokonek_user' || e.key === 'ecokonek_token') {
          try {
            const updatedUser = localStorage.getItem('ecokonek_user');
            const updatedToken = localStorage.getItem('ecokonek_token');
            if (updatedUser) {
              const u: MinimalUser = JSON.parse(updatedUser);
              setUserId(u?.id || null);
            } else {
              setUserId(null);
            }
            setHasToken(!!updatedToken);
          } catch {
            setUserId(null);
            setHasToken(false);
          }
        }
      };
      window.addEventListener('storage', onStorage);
      return () => window.removeEventListener('storage', onStorage);
    }
  }, []);

  // Don't show bell on excluded pages or when no user is logged in
  if (!userId || !hasToken || !pathname || EXCLUDED_PATHS.includes(pathname)) return null;
  
  return (
    <div className="fixed top-4 right-4 z-[9999]">
      <NotificationBell userId={userId} />
    </div>
  );
}
