'use client';

import { useEffect, useState } from 'react';
import { getClientSocket, disconnectClientSocket } from '../lib/socketClient';

interface Notification {
  id: string;
  recipient_id: string;
  sender_id: string | null;
  type: string;
  content: string;
  link?: string;
  aggregation_key?: string | null;
  count?: number;
  latest_actors?: Array<{ id: string; name?: string; avatar_url?: string }>;
  is_read: boolean;
  created_at: string;
  updated_at: string;
}

interface NotificationBellProps {
  userId: string;
}

export default function NotificationBell({ userId }: NotificationBellProps) {
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [unreadCount, setUnreadCount] = useState<number>(0);
  const [dropdownOpen, setDropdownOpen] = useState<boolean>(false);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function fetchNotifications() {
      setIsLoading(true);
      setError(null);
      try {
        let token = '';
        if (typeof window !== 'undefined') {
          token = localStorage.getItem('ecokonek_token') || '';
        }
        const res = await fetch('/api/notifications', {
          headers: {
            'Authorization': token ? `Bearer ${token}` : ''
          }
        });
        
        if (res.status === 401) {
          // Token is missing/expired/invalid. Clear stale token and gracefully exit.
          try {
            if (typeof window !== 'undefined') {
              localStorage.removeItem('ecokonek_token');
            }
          } catch {}
          setNotifications([]);
          setUnreadCount(0);
          setError('Sign in to see notifications');
          setIsLoading(false);
          return;
        }

        if (!res.ok) {
          // Non-OK (but not 401): show friendly error, don't throw
          setNotifications([]);
          setUnreadCount(0);
          setError(`Failed to load notifications (${res.status})`);
          setIsLoading(false);
          return;
        }
        
        let data = null;
        try {
          data = await res.json();
        } catch (err) {
          // Defensive: handle empty or invalid JSON
          console.error('[NotificationBell] JSON parse error:', err);
          setNotifications([]);
          setUnreadCount(0);
          setError('Failed to load notifications');
          return;
        }
        
        if (data && data.success) {
          setNotifications(data.notifications as Notification[]);
          setUnreadCount((data.notifications as Notification[]).filter((n: Notification) => !n.is_read).length);
        } else {
          setError(data?.error || 'Failed to load notifications');
        }
      } catch (err: any) {
        console.error('[NotificationBell] Fetch error:', err);
        setError(err.message || 'Something went wrong');
      } finally {
        setIsLoading(false);
      }
    }
    fetchNotifications();
  }, []);

  useEffect(() => {
    if (!userId) return;
    // Connect via shared singleton to avoid duplicate connections
    const socket = getClientSocket(userId);
    // Ensure we don't double-register handlers if the effect re-runs
    const onConnect = () => {
      console.log('[socket] connected', socket.id);
    };
    const onDisconnect = (reason: string) => {
      console.log('[socket] disconnected', socket.id, 'reason:', reason);
    };
    const onNew = (notification: Notification) => {
      setNotifications(prev => [notification, ...prev]);
      setUnreadCount(prev => prev + 1);
    };
    const onUpdated = (notification: Notification) => {
      setNotifications(prev => {
        const idx = prev.findIndex(n => n.id === notification.id);
        if (idx === -1) return [notification, ...prev];
        const copy = [...prev];
        copy[idx] = notification;
        return copy;
      });
    };

    // Remove existing listeners before adding
    socket.off('new-notification');
    socket.off('notification_updated');
    if (process.env.NODE_ENV !== 'production') {
      socket.off('connect');
      socket.off('disconnect');
      socket.on('connect', onConnect);
      socket.on('disconnect', onDisconnect);
    }
    socket.on('new-notification', onNew);
    socket.on('notification_updated', onUpdated);

    return () => {
      // Clean up listeners on unmount to avoid duplicates during Fast Refresh/StrictMode
      socket.off('new-notification', onNew);
      socket.off('notification_updated', onUpdated);
      if (process.env.NODE_ENV !== 'production') {
        socket.off('connect', onConnect);
        socket.off('disconnect', onDisconnect);
      }
    };
  }, [userId]);

  function renderLabel(n: Notification) {
    const base = n.content || '';
    const count = n.count ?? 1;
    const actors = Array.isArray(n.latest_actors) ? n.latest_actors : [];
    if (actors.length > 0 && count > 1) {
      const first = actors[0];
      const name = first?.name || 'Someone';
      const others = count - 1;
      if (others === 1) return `${name} and 1 other ${base}`;
      if (others > 1) return `${name} and ${others} others ${base}`;
    } else if (actors.length > 0 && count === 1) {
      const first = actors[0];
      const name = first?.name || 'Someone';
      return `${name} ${base}`;
    }
    return base;
  }

  return (
    <div className="relative flex items-center">
      <button 
        onClick={() => setDropdownOpen(!dropdownOpen)} 
        className="relative p-2 hover:bg-gray-100 rounded-full transition-colors"
        aria-label="Notifications"
      >
        <i className="ri-notification-3-line text-2xl text-gray-700"></i>
        {unreadCount > 0 && (
          <span className="absolute top-0 right-0 bg-red-500 text-white rounded-full w-5 h-5 flex items-center justify-center text-xs font-bold">
            {unreadCount > 9 ? '9+' : unreadCount}
          </span>
        )}
      </button>
      {dropdownOpen && (
        <div className="absolute right-0 top-12 w-96 bg-white shadow-2xl rounded-xl z-50 border border-gray-200 max-h-[80vh] overflow-hidden flex flex-col">
          <div className="p-4 border-b font-semibold bg-gray-50 flex items-center justify-between">
            <span className="text-lg">Notifications</span>
            {unreadCount > 0 && (
              <button 
                className="text-sm text-green-600 hover:text-green-700 font-medium"
                onClick={() => {/* TODO: Mark all as read */}}
              >
                Mark all read
              </button>
            )}
          </div>
          <ul className="overflow-y-auto flex-1">
            {isLoading ? (
              <li className="p-8 text-center">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-green-600 mx-auto mb-2"></div>
                <p className="text-gray-500 text-sm">Loading notifications...</p>
              </li>
            ) : error ? (
              <li className="p-8 text-center">
                <i className="ri-error-warning-line text-4xl text-red-400 mb-2"></i>
                <p className="text-red-600 text-sm">{error}</p>
              </li>
            ) : notifications.length === 0 ? (
              <li className="p-8 text-center">
                <i className="ri-notification-off-line text-4xl text-gray-300 mb-2"></i>
                <p className="text-gray-500">No notifications</p>
              </li>
            ) : notifications.map(n => (
              <li 
                key={n.id} 
                className={`p-4 border-b hover:bg-gray-50 transition-colors ${n.is_read ? 'bg-white' : 'bg-blue-50'}`}
              >
                <a href={n.link || '#'} className="block">
                  <div className="flex items-start gap-3">
                    <div className={`w-2 h-2 rounded-full mt-2 flex-shrink-0 ${n.is_read ? 'bg-gray-300' : 'bg-blue-500'}`}></div>
                    <div className="flex-1 min-w-0">
                      <p className="text-sm text-gray-800 leading-relaxed">
                        {renderLabel(n)}
                      </p>
                      <div className="text-xs text-gray-400 mt-1">{new Date(n.created_at).toLocaleString()}</div>
                    </div>
                  </div>
                </a>
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}
