'use client';

import io from 'socket.io-client';

let socket: any = null;
let currentUserId: string | null = null;

export function getClientSocket(userId: string): any {
  // Reuse the same socket if already connected for this user
  if (socket && currentUserId === userId) {
    return socket;
  }

  // If a socket exists for a different user, disconnect first
  if (socket && currentUserId !== userId) {
    try { socket.disconnect(); } catch {}
    socket = null;
  }

  currentUserId = userId;
  // Use explicit origin to avoid ws/wss mismatch when site is served over https
  const origin = (typeof window !== 'undefined' && window.location && window.location.origin) ? window.location.origin : undefined

  const socketOptions = {
    path: '/api/socket',
    addTrailingSlash: false,
    // Default transports; may be overridden below for development stability
    transports: ['websocket', 'polling'],
    // Do not send cookies/credentials by default across origins (avoids CORS issues)
    withCredentials: false,
    reconnection: true,
    // Limit reconnection attempts to prevent infinite refresh loops
    reconnectionAttempts: 5,
    reconnectionDelay: 2000,
    reconnectionDelayMax: 10000,
    timeout: 20000,
    query: { userId }
  } as any;

  if (origin) {
    // If served over HTTPS, ensure secure connection for socket.io
    const secure = origin.startsWith('https:') || origin.startsWith('wss:')
    // For development stability across LANs/proxies, force polling transport.
    // This avoids repeated "transport close" disconnect loops while debugging.
    if (process.env.NODE_ENV !== 'production') {
      socket = io(origin, { ...socketOptions, secure, transports: ['polling'] })
    } else {
      socket = io(origin, { ...socketOptions, secure })
    }
  } else {
    socket = io(socketOptions as any)
  }

  // Optional: quiet noisy errors in production
  socket.on('connect_error', (err: unknown) => {
    const msg = (err as any)?.message ?? String(err ?? 'unknown error');
    const detail = (err as any)?.toString?.() || JSON.stringify(err);
    // Always log connect errors in dev; include stack/details when available
    if (process.env.NODE_ENV !== 'production') {
      console.warn('[socket] connect_error:', msg, detail, { userId, err });
    } else {
      // In production keep a concise warning
      console.warn('[socket] connect_error:', msg);
    }
  });

  // Only log critical socket events in development to reduce noise and improve performance
  socket.on('reconnect_failed', () => {
    if (process.env.NODE_ENV !== 'production') {
      console.warn('[socket] reconnection failed after maximum attempts');
    }
  });
  
  socket.on('disconnect', (reason: string) => {
    if (process.env.NODE_ENV !== 'production' && reason === 'io server disconnect') {
      console.warn('[socket] server disconnected client');
    }
  });

  return socket;
}

export function disconnectClientSocket() {
  try { socket?.disconnect(); } catch {}
  socket = null;
  currentUserId = null;
}
